#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int a[15];
        for(int i=0;i<N;i++) scanf("%d",&a[i]);
        int total = 1<<N;
        printf("[\n");
        for(int mask=0; mask<total; ++mask){
            printf("[");
            int first=1;
            for(int i=0;i<N;i++) if(mask & (1<<i)){
                if(!first) printf(", ");
                printf("%d",a[i]);
                first=0;
            }
            printf("]\n");
        }
        printf("]\n");
    }
    return 0;
}

