import sys
def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        total = 1 << N
        out.append('[')
        for mask in range(total):
            subset = []
            for i in range(N):
                if mask & (1 << i):
                    subset.append(str(arr[i]))
            out.append('[' + (', '.join(subset)) + ']')
        out.append(']')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    main()

